name: Workflows Approve
on:
  pull_request_target:
    types: [labeled, synchronize]
jobs:
  approve:
    runs-on: ubuntu-latest
    if: github.event.action == 'labeled' || github.event.action == 'synchronize'
    permissions:
      actions: write
      pull-requests: read
    steps:
      - name: Check contributor
        id: check
        uses: actions/github-script@v7
        with:
          script: |
            const { data: prs } = await github.rest.pulls.list({
              owner: context.repo.owner,
              repo: context.repo.repo,
              state: 'all',
              head: `${context.payload.pull_request.head.repo.owner.login}:${context.payload.pull_request.head.ref}`
            });
            const contributorPrs = prs.filter(pr => pr.user.login === context.payload.pull_request.user.login);
            const hasOkToTest = context.payload.pull_request.labels.some(label => label.name === 'ok-to-test');
            const shouldApprove = contributorPrs.length > 1 || hasOkToTest;
            core.setOutput('should_approve', shouldApprove);
      - name: Approve workflows
        if: steps.check.outputs.should_approve == 'true'
        uses: actions/github-script@v7
        with:
          script: |
            const runs = await github.rest.actions.listWorkflowRunsForRepo({
              owner: context.repo.owner,
              repo: context.repo.repo,
              status: 'action_required',
              head_sha: context.payload.pull_request.head.sha
            });
            for (const run of runs.data.workflow_runs) {
              await github.rest.actions.approveWorkflowRun({
                owner: context.repo.owner,
                repo: context.repo.repo,
                run_id: run.id
              });
            }

