from dify_plugin import Plugin, DifyPluginEnv


def main():
    Plugin(DifyPluginEnv(MAX_REQUEST_TIMEOUT=120)).run()


if __name__ == "__main__":
    main()

from dify_plugin import ToolProvider
from dify_plugin.errors.tool import ToolProviderCredentialValidationError


class AgentcubeCodeInterpreterProvider(ToolProvider):
    def _validate_credentials(self, credentials: dict) -> None:
        try:
            router_url = credentials.get("router_url")
            workload_manager_url = credentials.get("workload_manager_url")
            if not router_url:
                raise ToolProviderCredentialValidationError("router_url is required")
            if not workload_manager_url:
                raise ToolProviderCredentialValidationError("workload_manager_url is required")
        except ToolProviderCredentialValidationError:
            raise
        except Exception as e:
            raise ToolProviderCredentialValidationError(str(e))

import base64
from typing import Generator
from dify_plugin import Tool
from dify_plugin.entities.tool import ToolInvokeMessage


class AgentcubeCodeInterpreterTool(Tool):
    def _invoke(self, tool_parameters: dict) -> Generator[ToolInvokeMessage, None, None]:
        result = self.execute(**tool_parameters)
        yield self.create_json_message(result)

    def execute(
        self,
        router_url: str,
        workload_manager_url: str,
        language: str = "python",
        code_interpreter_id: str = None,
        session_id: str = None,
        code: str = None,
        command: str = None,
        session_reuse: bool = False,
        **kwargs,
    ) -> dict:
        try:
            from agentcube import CodeInterpreterClient
        except ImportError:
            return {"error": "agentcube-sdk is not installed", "success": False}

        if not code_interpreter_id:
            code_interpreter_id = "default"

        try:
            client = CodeInterpreterClient(
                name=code_interpreter_id,
                namespace="default",
                router_url=router_url,
                workload_manager_url=workload_manager_url,
                session_id=session_id if session_reuse else None,
            )
        except Exception as e:
            return {"error": str(e), "success": False}

        result = {"success": True, "session_id": None}

        try:
            if code:
                exec_result = client.run_code(language=language, code=code)
                result["stdout"] = exec_result.get("stdout", "")
                result["stderr"] = exec_result.get("stderr", "")
                result["exit_code"] = exec_result.get("exit_code", 0)
            elif command:
                exec_result = client.execute_command(command=command)
                result["stdout"] = exec_result.get("stdout", "")
                result["stderr"] = exec_result.get("stderr", "")
                result["exit_code"] = exec_result.get("exit_code", 0)
            else:
                result["error"] = "Either code or command must be provided"
                result["success"] = False

            if session_reuse:
                result["session_id"] = client.session_id

        except Exception as e:
            result["error"] = str(e)
            result["success"] = False
        finally:
            if not session_reuse:
                client.stop()

        return result
